def validate_emotion_coverage(image_plan: list) -> dict:
    """Validate all sections have emotion assignments."""
    required_sections = [
        "hero", "pain", "story", "mechanism", 
        "proof", "offer", "guarantee", "cta"
    ]

    covered = set()
    for img in image_plan:
        section = img.get("section", "").lower()
        for req in required_sections:
            if req in section:
                covered.add(req)

    missing = [s for s in required_sections if s not in covered]
    coverage = len(covered) / len(required_sections)

    return {
        "passed": coverage >= 0.75,
        "coverage": round(coverage * 100),
        "covered_sections": list(covered),
        "missing_sections": missing
    }


def check_pain_relief_pairing(image_plan: list) -> dict:
    """Check pain → relief visual pairings exist."""
    before_images = [i for i in image_plan if "before" in i.get("tags", [])]
    after_images = [i for i in image_plan if "after" in i.get("tags", [])]

    has_pairing = len(before_images) > 0 and len(after_images) > 0

    issues = []
    if len(before_images) == 0:
        issues.append("No 'before' state images defined")
    if len(after_images) == 0:
        issues.append("No 'after' state images defined")
    if len(before_images) != len(after_images):
        issues.append("Before/after count mismatch - should be paired")

    return {
        "passed": has_pairing and len(issues) == 0,
        "before_count": len(before_images),
        "after_count": len(after_images),
        "issues": issues
    }


def score_authenticity(image_concept: dict) -> dict:
    """Score image concept for authenticity."""
    concept = str(image_concept.get("concept", "")).lower()

    score = 10  # Start at max, deduct for red flags
    issues = []

    # Stock photo red flags
    stock_flags = [
        "pointing at", "handshake", "thumbs up", "fist bump",
        "perfect", "generic", "corporate", "posed"
    ]
    for flag in stock_flags:
        if flag in concept:
            score -= 2
            issues.append(f"Stock photo indicator: '{flag}'")

    # Authenticity boosters
    auth_signals = [
        "messy", "lived-in", "candid", "natural", "real",
        "wrinkles", "tired", "specific", "kitchen", "home office"
    ]
    for signal in auth_signals:
        if signal in concept:
            score += 0.5

    score = max(0, min(10, score))
    passed = score >= 7

    return {
        "passed": passed,
        "score": round(score, 1),
        "issues": issues,
        "recommendation": "Increase specificity" if not passed else "Authentic"
    }


def validate_ethical_bounds(image_concept: dict) -> dict:
    """Validate image concept against ethical guidelines."""
    concept = str(image_concept.get("concept", "")).lower()

    violations = []

    # Prohibited patterns
    prohibited = {
        "magic cure": ["miracle", "instant", "magic"],
        "fear porn": ["graphic", "gore", "disaster", "crisis"],
        "exploitation": ["humiliat", "shame", "exposed"],
        "misrepresentation": ["fake doctor", "fake hospital", "fake credential"]
    }

    for category, keywords in prohibited.items():
        for kw in keywords:
            if kw in concept:
                violations.append(f"{category}: contains '{kw}'")

    passed = len(violations) == 0

    return {
        "passed": passed,
        "violations": violations,
        "recommendation": "Revise concept" if not passed else "Within ethical bounds"
    }
